UPDATE MSF_REQUEST_OSST
SET AMD_DT = NOW()
, PRGR_STAT_CD    = #{prgrStatCd}
, OSST_ORD_NO    = #{osstOrdNo}
, RSLT_CD        = #{rsltCd}
, RSLT_MSG       = #{rsltMsg}
, TLPH_NO        = #{tlphNo}
, TLPH_NO_STAT_CD     = #{tlphNoStatCd}
, ENCD_TLPH_NO        = #{encdTlphNo}
, TLPH_NO_OWN_CMPN_CD = #{tlphNoOwnCmpnCd}
, ASGN_AGNC_ID        = #{asgnAgncId}
, OPEN_SVC_IND_CD     = #{openSvcIndCd}
, NSTEP_GLOBAL_ID     = #{nstepGlobalId}
WHERE REQUEST_KEY = #{requestKey}

UPDATE MSF_REQUEST
SET AMD_DT = NOW()
, OPEN_NO   = #{openNo}
, SCAN_ID   = #{scanId}
, PRO_STTUS_CD = #{proCd}
WHERE REQUEST_KEY = #{requestKey}
